<template>
  <div class="box-card" ref="mainCard" id="mainCard">

    <el-tabs :tab-position="tabPosition" style="min-height: 150px" class="demo-tabs" @tab-change="changeGitGroup" v-model="chooseGroupId">
      <el-tab-pane v-for="(groupInfo, k) in gitGroupConfigList" :key="k" :label="groupInfo.name" :name="groupInfo.id">
        <el-row :gutter="20">
          <template v-for="(value, key) in gitConfigList">
            <el-col :span="2" style="margin-top:5px;" v-if="value.git_group_id === groupInfo.id">
              <div>
                <el-radio @change="ChangeGit(value)" size="large" v-model="chooseGitId" :label="value.id">{{ value.name }}
                </el-radio>
              </div>
            </el-col>
          </template>
        </el-row>
      </el-tab-pane>
    </el-tabs>
    <el-button type="primary" v-loading="btnLoading.pull" @click="GitPullBranchOrigin">拉取最新代码</el-button>
    <el-button type="primary" v-loading="btnLoading.status" @click="GitQueryStatus">查看分支变更</el-button>
    <el-input v-if="showChangeBranch" style="width: 300px; margin-right: 20px" v-model="BranchName" placeholder="请输入分支名"></el-input>
    <el-button type="primary" v-loading="btnLoading.change" @click="GitChangeBranch">切换分支</el-button>
    <el-button type="primary" v-loading="btnLoading.query" @click="queryCurrentBranch">查看分支</el-button>
    <el-button type="primary" v-loading="btnLoading.queryLog" @click="queryCommitLog">查看提交日志
    </el-button>
  </div>
  <p></p>
  <shellResult ref="shellRef" :shellShowResult="shellController.sshResult" :divHeight="shellController.divHeight" :isRunning="shellController.isRunning" :show-model="shellController.showModel"></shellResult>

</template>
<style>
.text {
  font-size: 14px;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.item {
  margin-bottom: 10px;
}

</style>
<script>
import git from '../utils/base/git.js'
import base from '../utils/base'
import shell from "@/utils/base/shell"
import socket from "@/utils/base/socket"
import shellResult from "@/components/shell/result.vue";
import format from "@/utils/base/format";

export default {
  props: {
  },
  components: {
    shellResult,
  },
  data() {
    return {
      //shell
      shellController: {
        sshResult: '',
        isRunning: false,
        showModel: 'div',
        divHeight: 250,
      },
      name: 'Git',
      //输入框
      showChangeBranch: false,
      tabPosition: 'top',
      //按钮状态
      btnLoading: {
        exec: false,
        pull: false,
        change: false,
        status: false,
        query: false,
      },
      BranchName: '', //分支名
      gitGroupConfigList : [],
      gitConfigList : [],
      selectGitConfig : {},
      chooseGroupId : 0,
      chooseGitId : 0,
    }
  },
  mounted: function () {
    let _that = this
    base.PageInit(_that.name,
        function (boolInit) {
          _that.GetGitConfigList()
        }, function (boolInit) {

          _that.windowChange()
        })
  },
  activated: function () {
  },
  methods: {
    chooseDefault : function (){
      let _that = this
      //初始化默认选中的分组和git
      _that.chooseGroupId = git.GitLocalGetLastGroupId()
      _that.chooseGitId = git.GitLocalGetLastGitId()
      console.log(_that.gitConfigList)
      for (let i in _that.gitConfigList){
        if(parseInt(_that.gitConfigList[i].id) === parseInt(_that.chooseGitId)){
          _that.selectGitConfig = _that.gitConfigList[i]
        }
      }
      console.log(_that.selectGitConfig , _that.chooseGitId)
      if(_that.selectGitConfig && _that.selectGitConfig.id){
        _that.ChangeGit(_that.selectGitConfig)
      }
    },
    windowChange : function (){
      let _that = this
      window.addEventListener('resize', function () {
        shell.calculateShellDivHeight(_that)
      });
    },
    //切换选择git
    ChangeGit : function (selectGitConfig){
      let _that = this
      _that.selectGitConfig = selectGitConfig
      _that.chooseGitId = selectGitConfig.id
      _that.queryCurrentBranch()
      shell.calculateShellDivHeight(_that)
      git.GitLocalSetLastGitId(_that.selectGitConfig.id)
      socket.SocketCreate(_that.selectGitConfig.ssh_id , 'git' , 500 , function (totalReceiveMsg){
        _that.shellController.sshResult = format.formatResult(totalReceiveMsg, ['copy', 'color', 'replace'])
        _that.shellController.sshResult = format.formatResult(_that.shellController.sshResult, ['length'])
      })
    },
    //获取git和git group列表
    GetGitConfigList : function (){
      let _that = this
      git.GitConfigList(function (response){
        if(response.ErrCode === 0 ){
          _that.gitConfigList = response.Data.git_list
          _that.gitGroupConfigList = response.Data.git_group_list
          _that.chooseDefault()
        }else{
          _that.$helperNotify.error('失败')
        }
      })
    },
    //切换分组
    changeGitGroup: function () {
      let _that = this
      git.GitLocalSetLastGroupId(_that.chooseGroupId)
      if(_that.gitConfigList.length === 0){
        return
      }
      _that.ChangeGit(_that.gitConfigList[0])
    },
    //查询分支
    queryCurrentBranch: function () {
      let _that = this
      _that.showChangeBranch = false
      _that.btnLoading.query = true
      git.GitCurrentBranch(_that.selectGitConfig, function (response) {
        setTimeout(function () {
          _that.btnLoading.query = false
        }, 500)
      })
    },
    //查询commit log
    queryCommitLog: function () {
      let _that = this
      _that.btnLoading.queryLog = true
      git.GitCommitLog(_that.selectGitConfig, function (response) {
        setTimeout(function () {
          _that.btnLoading.queryLog = false
        }, 500)
      })
    },
    //拉取代码
    GitPullBranchOrigin: function () {
      let _that = this
      _that.btnLoading.pull = true
      git.GitPullBranchOrigin(_that.selectGitConfig,  function (response) {
        setTimeout(function () {
          _that.btnLoading.pull = false
        }, 500)
      })
    },
    //查询状态
    GitQueryStatus: function () {
      let _that = this
      _that.btnLoading.status = true
      git.GitQueryStatus(_that.selectGitConfig, function (response) {
        setTimeout(function () {
          _that.btnLoading.status = false
        }, 500)
      })
    },
    //切换分支
    GitChangeBranch: function () {
      if (!this.showChangeBranch) {
        this.showChangeBranch = true
        return
      }
      let _that = this
      _that.btnLoading.change = true
      git.GitChangeBranch(_that.selectGitConfig, _that.BranchName, function (response) {
            _that.showChangeBranch = false
            setTimeout(function () {
              _that.btnLoading.change = false
            }, 500)
          }
      )
    },
  },
}
</script>

<style scoped></style>
